#include <bits/stdc++.h>
using namespace std;
int r,l;
int p[10100];
void push(int y){
    p[r]=y;
    r++;
}
int top(){
    return p[l];
}
void pop(){
    l++;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=0;i<n;i++){
        p[i]=i+1;
        r++;
    }
    for(int i=0;i<n;i++){
        for(int j=0;j<m-1;j++){
            push(top());
            pop();
        }
        cout<<top()<<" ";
        pop();
    }
    return 0;
}
